#include <omp.h>
#include <math.h> // For exp
#include "../main.h"
#include "../util/timer/timer.h"

// Define DOT macro locally if not globally available or if it needs specific types
#ifndef DOT
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))
#endif

void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv)
{
    // Parameters
    fp a2 = 2.0 * par.alpha * par.alpha;

    // OpenMP parallel region
    #pragma omp parallel
    {
        // Thread-local variables to avoid race conditions and for shared memory simulation
        FOUR_VECTOR rA_local[NUMBER_PAR_PER_BOX];
        FOUR_VECTOR fA_local[NUMBER_PAR_PER_BOX];
        FOUR_VECTOR rB_local[NUMBER_PAR_PER_BOX];
        fp qB_local[NUMBER_PAR_PER_BOX];

        // Initialize local force accumulators for each thread
        #pragma omp for nowait schedule(static)
        for (int i = 0; i < dim.space_elem; ++i) {
            fv[i].v = 0.0;
            fv[i].x = 0.0;
            fv[i].y = 0.0;
            fv[i].z = 0.0;
        }

        // Main loop over boxes
        #pragma omp for schedule(static) nowait
        for (int bx = 0; bx < dim.number_boxes; ++bx) {

            // Home box parameters
            int first_i = box[bx].offset;

            // Copy home box particle data to local storage
            for (int tx = 0; tx < NUMBER_PAR_PER_BOX; ++tx) {
                rA_local[tx] = rv[first_i + tx];
                fA_local[tx] = fv[first_i + tx]; // Initialize local accumulator
            }

            // Loop over neighboring boxes
            for (int k = 0; k < (1 + box[bx].nn); ++k) {
                int pointer;
                if (k == 0) {
                    pointer = bx; // Home box
                } else {
                    pointer = box[bx].nei[k - 1].number; // Neighbor box
                }

                // Neighbor box parameters
                int first_j = box[pointer].offset;

                // Copy neighbor box particle data to local storage
                for (int tx = 0; tx < NUMBER_PAR_PER_BOX; ++tx) {
                    rB_local[tx] = rv[first_j + tx];
                    qB_local[tx] = qv[first_j + tx];
                }

                // Calculation loop
                for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; ++wtx) { // Loop for particles in home box
                    for (int j = 0; j < NUMBER_PAR_PER_BOX; ++j) { // Loop for particles in neighbor box

                        fp r2;
                        fp u2;
                        fp vij;
                        fp fs;
                        fp fxij;
                        fp fyij;
                        fp fzij;
                        THREE_VECTOR d;

                        // Calculate distance squared and related terms
                        r2 = (fp)rA_local[wtx].v + (fp)rB_local[j].v - DOT((fp)rA_local[wtx], (fp)rB_local[j]);
                        u2 = a2 * r2;
                        vij = exp(-u2);
                        fs = 2.0 * vij;

                        // Calculate force components
                        d.x = (fp)rA_local[wtx].x - (fp)rB_local[j].x;
                        fxij = fs * d.x;
                        d.y = (fp)rA_local[wtx].y - (fp)rB_local[j].y;
                        fyij = fs * d.y;
                        d.z = (fp)rA_local[wtx].z - (fp)rB_local[j].z;
                        fzij = fs * d.z;

                        // Accumulate forces in local storage
                        fA_local[wtx].v += (double)((fp)qB_local[j] * vij);
                        fA_local[wtx].x += (double)((fp)qB_local[j] * fxij);
                        fA_local[wtx].y += (double)((fp)qB_local[j] * fyij);
                        fA_local[wtx].z += (double)((fp)qB_local[j] * fzij);
                    }
                }
            }

            // Write accumulated forces back to global memory
            for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; ++wtx) {
                fv[first_i + wtx].v += fA_local[wtx].v;
                fv[first_i + wtx].x += fA_local[wtx].x;
                fv[first_i + wtx].y += fA_local[wtx].y;
                fv[first_i + wtx].z += fA_local[wtx].z;
            }
        }
    }
}
